import{_ as a,o as r,c as e,an as o,ao as i,ap as l}from"./chunks/framework.CwJEbcdc.js";const m=JSON.parse('{"title":"关于AI的一些认识","description":"","frontmatter":{},"headers":[],"relativePath":"AI/youtube.md","filePath":"AI/youtube.md","lastUpdated":1758730366000}'),s={name:"AI/youtube.md"};function n(p,t,u,b,A,I){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="关于ai的一些认识" tabindex="-1">关于AI的一些认识 <a class="header-anchor" href="#关于ai的一些认识" aria-label="Permalink to “关于AI的一些认识”">​</a></h1><ol><li>总结无意间看到Youtube上关于AI的一个视频收获</li><li>结合自己的生活聊聊关于AI的使用</li></ol><h2 id="youtube视频总结" tabindex="-1">Youtube视频总结 <a class="header-anchor" href="#youtube视频总结" aria-label="Permalink to “Youtube视频总结”">​</a></h2><p>你说,能不能用AI为我总结一下呢?可以肯定是可以的,不过我想先发挥一下自己&quot;逐渐被侵蚀的&quot;,思考总结能力:<br> 涵盖的AI有: Chat GPT, Gemini, Google Lab, Grok.</p><ol><li><p>Chat GPT输入Prompt的新用法:<br><strong>QuizGPT Flashcard: Javascript Basics</strong>. Javascript Basics是你输入的内容,前面是告诉GPT的Prompt.这条Prompt会生成关于Javascript基础的一些小测试.<br> 测试由Flashcards组成,提供4个选项和正确答案.(没有答案解析是否可以改进?)<br> 测试结束后有新的按钮,接着生成相关主题的其它测试.(所以理论上可以一直测试下去) <img src="'+i+'" alt="flashcard"></p></li><li><p>Gemini生成storybook <a href="https://gemini.google.com/gem/storybook/" target="_blank" rel="noreferrer">Geministorybook的地址</a>. 输入你想生成的内容,就会根据Prompt生成带有图片和文字描述的,相关的&quot;故事书&quot;</p></li><li><p>Gemini利用提问方式,一步一步引导提问者,自行思考得出答案<br><a href="https://gemini.google.com/app" target="_blank" rel="noreferrer">Gemini的地址</a>, 就是一个选项:<strong>学习辅导</strong>. 实际更像&quot;举一反三&quot;, 先给出你提问的答案,再向你引申其它问题,让你知其然且知其所以然.</p></li><li><p>Google Lab的Talking Tour.<br> 选择你想去的世界某个地方,AI会生成对应地点的3D景象,你可以&quot;拍照&quot;,对某一景象进行提问,AI这个&quot;导游&quot;会根据你的问题进行回答,让你有身临其境的感觉.</p></li><li><p>Grok App的Imagine 功能<br> 是App里才有的功能,<strong>简直令人印象深刻</strong>.<br> 简单说是根据你的描述生成对应图片,之后可以使图片&quot;动起来&quot;,不仅可以变成动画,还可以生成图片声音.<br> 重点来了:生成的动画是可以根据你的选择的模式进行修改的.分别有:Normal, Fun, <strong>Spicy</strong>, <strong>自订</strong>.<br> 没错,Grok AI能火的一个原因就是,可以生成&quot;最具原始动力&quot;的动画.(所以说我为什么会对这个功能印象深刻...)</p></li></ol><h2 id="关于ai的使用" tabindex="-1">关于AI的使用 <a class="header-anchor" href="#关于ai的使用" aria-label="Permalink to “关于AI的使用”">​</a></h2><p>读到一篇关于AI的文章.<a href="https://mp.weixin.qq.com/s/FYr4eFJxEZLWUXOGhnkIqQ" target="_blank" rel="noreferrer">数字生命卡兹克的关于AI的看法</a><br> 说实话,我也被震撼到了.<br> 起因是作者在淘宝上看到的,售卖9.9元&quot;满血版&quot;DeepSeek的商品.他作为新媒体作者,也很可能是开发者,抱着好奇心就买了这个多达近1000元付款的商品.<br> 结果是下单后商家给他发了几个链接,给他跳转到几个其它免费AI产品,甚至宣言,&quot;什么?你居然都有了?那我大发慈悲再给你发一个更好用的AI好了!&quot;<br> 不出所料,得到的是另外一个也是免费的AI产品.<br> 作者将他看过的书,跟AI结合,将现在大部分人在使用AI方面分为三个层级:</p><ol><li>AI工具的前沿开发者,深知AI的运行逻辑,熟练使用甚至整合开发最新的AI工具</li><li>略有基础的AI工具使用者. 知道基础的AI功能,起码知道哪些AI是比较出名,哪些AI是免费,AI的哪些功能是需要付费的.</li><li>使用AI工具的&quot;小白&quot;.&quot;一问一答&quot;足以满足自身需求,不知道AI的答案是怎么来的,答案是否权威正确,只要自己的问题得到解答就好.什么模型,什么API,什么MCP,一无所知.</li></ol><p>而我自己虽然是计算机专业的,但隔行如隔山,学的不是AI大数据python这些,勉强自诩为2/3阶层之人.<br> 我是22年7月(自己都震惊了这么早)接触的Chat GPT,而Deepseek大火我查了下是在25年的1月,是模型开源,让人人都有机会轻松接触到AI的力量了. <img src="'+l+'" alt="my-ai-history"></p><p>最初我记得访问网页版的Chat GPT是要手动添加token到请求中才能正常使用的,token好像是3个月的期限.(现在根本就不需要这一步).<br> 说起来还有点自豪,像新认识了一位&quot;有求必应的朋友&quot;.什么问题我都可以问它,它也什么都可以回应我.<br> 当时我不会怀疑它回答的正确性,只是认为它是&quot;无所不知&quot;的.<br> 眨眼三年过去了,Chat GPT也不再一枝独秀,后起之秀如上面的Deepseek,Gemini,Claude, 国产的文心一言(百度),通义灵码(阿里).更有直接整合不同模型的应用,略微切换就能用上成千上百种不同的模型,得到不同粒度的结果.</p><p>现在我们会烦父母不会使用手机,胡乱下载这个应用那个应用;你说到了若干年后,我们的孩子会不会也会烦我们,不会用这个AI那个AI呢?<br> 我们会不会因为信息的爆炸,更早地被孩子们给嫌弃,被信息时代的浪潮给淘汰呢?</p><p>还好我们还不算太老,我们目前还是社会的主力,未来是你们的,现在暂时还是我们的.</p><p>半个月前,新款的iPhone 17发布了,国行iPhone因为政治原因被阉割了AI功能,我也无意看到何同学的手机测评,其中就有他对未来AI嵌入到手机后,如何更方便我们生活的畅想.<br> 半个月后,代表国产的华为也发布了FreeClip 2耳机,其中就有利用AI实现同声传译的功能.<br> 不知为何我竟有点担忧: 我们选择的科技,会不会因为AI的使用/缺失,而领先/落后于世界?没有了AI,未来我们是否就无法享受更多新的功能便利?<br> AI无疑是强大的,我们想利用好它,就要向它暴露大量个人信息.<br> 信息重要还是方便重要?其中可能牵涉太多话题,我也不好继续&quot;遐想&quot;了.(真不是我也不知道答案)</p><h2 id="彩蛋-利用ai为我们总结一下视频内容" tabindex="-1">彩蛋:利用AI为我们总结一下视频内容 <a class="header-anchor" href="#彩蛋-利用ai为我们总结一下视频内容" aria-label="Permalink to “彩蛋:利用AI为我们总结一下视频内容”">​</a></h2><p>(扔给Chat GPT直接给我跳转到其它AI,将内容变成文字版了,我都不知道它总结了什么,虽然内容是对的,但summary是一点没体现出来)<br><a href="https://galaxy.ai/youtube-summarizer/five-exciting-ai-updates-you-need-to-know-about-be5KYtK4DIs?utm_source=chatgpt.com" target="_blank" rel="noreferrer">视频变文字稿了</a><br> 探索了一下 <a href="https://www.galaxy.ai" target="_blank" rel="noreferrer">https://www.galaxy.ai</a> 这个网站,感觉又打开新世界了.虽然看起来也不是免费的样子.</p>',15)])])}const c=a(s,[["render",n]]);export{m as __pageData,c as default};
